#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int n,m,p[N],t[4*N];
void Build(int cur,int l,int r){
    if(l==r){
        t[cur]=p[l];
        return;
    }
    int mid=(l+r)/2;
    Build(cur*2,l,mid);
    Build(cur*2+1,mid+1,r);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}
void Modify(int cur,int l,int r,int a,int b){
    if(l==r && l==a){
        p[a]=b;
        t[cur]=b;
        return;
    }
    int mid=(l+r)/2;
    if(a<=mid)
        Modify(cur*2,l,mid,a,b);
    else
        Modify(cur*2+1,mid+1,r,a,b);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}
int Find(int cur,int l,int r,int a,int b){
    if(l==a && r==b)
        return t[cur];
    int mid=(l+r)/2;
    if(b<=mid)
        return Find(cur*2,l,mid,a,b);
    else if(a>mid)
        return Find(cur*2+1,mid+1,r,a,b);
    else{
        int x=Find(cur*2,l,mid,a,mid),y=Find(cur*2+1,mid+1,r,mid+1,b);
        return max(x,y);
    }
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>p[i];
    Build(1,1,n);
    while(m--){
        char op;
        int a,b;
        cin>>op>>a>>b;
        if(op=='Q')
            cout<<Find(1,1,n,a,b)<<'\n';
        else if(op=='U')
            if(p[a]<b)
                Modify(1,1,n,a,b);
    }
    return 0;
}
